      font-size: 32px;
      color: #ffffff;
      line-height: 1.2;
      font-weight: 400;
    }

    .header h1 span {
      color: #8dbe9a;
    }

    /* Body */
    .body {
      padding: 44px 48px;
    }

    .greeting {
      font-size: 16px;
      color: #555;
      margin-bottom: 20px;
      line-height: 1.6;
    }

    .greeting strong {
      color: #1a2e22;
      font-weight: 600;
    }

    .message {
      font-size: 15px;
      line-height: 1.75;
      color: #444;
      margin-bottom: 32px;
    }

    /* Status card */
    .status-card {
      background: #f6f9f6;
      border-left: 3px solid #1a2e22;
      border-radius: 0 6px 6px 0;
      padding: 20px 24px;
      margin-bottom: 36px;
