for (const item of $input.all()) {
  const loanAmount = parseFloat(item.json['loan amount requested']) || 0;
  const interestRate = 0.08; // 8% for 500k to 1M salary tier
  const TERM = 12;

  const totalInterest    = loanAmount * interestRate * TERM;
  const totalPayable     = loanAmount + totalInterest;
  const monthlyRepayment = totalPayable / TERM;

  const fmt = (n) => "₦" + n.toLocaleString("en-NG", {
    minimumFractionDigits: 2,
    maximumFractionDigits: 2
  });

  item.json.interest_rate_percent  = "8%";
  item.json.loan_term_months       = TERM;
  item.json.total_interest         = fmt(totalInterest);
  item.json.total_payable          = fmt(totalPayable);
  item.json.monthly_repayment      = fmt(monthlyRepayment);
  item.json.total_payable_raw      = totalPayable.toFixed(2);
  item.json.monthly_repayment_raw  = monthlyRepayment.toFixed(2);
}

return $input.all();

